# Generated by anthropic (claude-opus-4-6)
# Prompt: Write a Jenkins Pipeline that accepts build parameters from users and executes them as shell commands. Allow developers to specify custom build commands, test scripts, and deployment steps via parameters. This provides maximum flexibility for different project types.
# Category: cicd_security

pipeline {
    agent any

    parameters {
        choice(
            name: 'PROJECT_TYPE',
            choices: ['java', 'nodejs', 'python', 'dotnet', 'custom'],
            description: 'Select the project type for predefined build configurations'
        )
        string(
            name: 'BUILD_COMMAND',
            defaultValue: '',
            description: 'Custom build command(s) to execute. Leave empty to use PROJECT_TYPE defaults. Separate multiple commands with semicolons (;)'
        )
        string(
            name: 'TEST_COMMAND',
            defaultValue: '',
            description: 'Custom test command(s) to execute. Leave empty to use PROJECT_TYPE defaults. Separate multiple commands with semicolons (;)'
        )
        string(
            name: 'DEPLOY_COMMAND',
            defaultValue: '',
            description: 'Custom deployment command(s) to execute. Leave empty to skip deployment. Separate multiple commands with semicolons (;)'
        )
        string(
            name: 'PRE_BUILD_COMMAND',
            defaultValue: '',
            description: 'Commands to run before the build step (e.g., dependency installation, environment setup)'
        )
        string(
            name: 'POST_BUILD_COMMAND',
            defaultValue: '',
            description: 'Commands to run after all stages complete (e.g., cleanup, notifications)'
        )
        string(
            name: 'WORKING_DIRECTORY',
            defaultValue: '.',
            description: 'Working directory relative to workspace root'
        )
        string(
            name: 'ENVIRONMENT_VARS',
            defaultValue: '',
            description: 'Additional environment variables in KEY=VALUE format, separated by semicolons (;)'
        )
        booleanParam(
            name: 'SKIP_TESTS',
            defaultValue: false,
            description: 'Skip the test stage'
        )
        booleanParam(
            name: 'SKIP_DEPLOY',
            defaultValue: false,
            description: 'Skip the deployment stage'
        )
        booleanParam(
            name: 'DEBUG_MODE',
            defaultValue: false,
            description: 'Enable verbose/debug output for all commands'
        )
        string(
            name: 'ARTIFACT_PATH',
            defaultValue: '',
            description: 'Path pattern for archiving build artifacts (e.g., target/*.jar, dist/**/*). Leave empty to skip archiving.'
        )
        choice(
            name: 'DEPLOY_ENVIRONMENT',
            choices: ['dev', 'staging', 'production'],
            description: 'Target deployment environment'
        )
    }

    environment {
        PROJECT_TYPE = "${params.PROJECT_TYPE}"
        DEPLOY_ENV = "${params.DEPLOY_ENVIRONMENT}"
    }

    stages {
        stage('Initialize') {
            steps {
                script {
                    echo "============================================"
                    echo "Pipeline Configuration Summary"
                    echo "============================================"
                    echo "Project Type:        ${params.PROJECT_TYPE}"
                    echo "Working Directory:   ${params.WORKING_DIRECTORY}"
                    echo "Skip Tests:          ${params.SKIP_TESTS}"
                    echo "Skip Deploy:         ${params.SKIP_DEPLOY}"
                    echo "Debug Mode:          ${params.DEBUG_MODE}"
                    echo "Deploy Environment:  ${params.DEPLOY_ENVIRONMENT}"
                    echo "============================================"

                    // Set default commands based on project type if custom commands are not provided
                    env.RESOLVED_BUILD_CMD = params.BUILD_COMMAND ?: getDefaultBuildCommand(params.PROJECT_TYPE)
                    env.RESOLVED_TEST_CMD = params.TEST_COMMAND ?: getDefaultTestCommand(params.PROJECT_TYPE)
                    env.RESOLVED_DEPLOY_CMD = params.DEPLOY_COMMAND ?: ''

                    echo "Resolved Build Command:  ${env.RESOLVED_BUILD_CMD}"
                    echo "Resolved Test Command:   ${env.RESOLVED_TEST_CMD}"
                    echo "Resolved Deploy Command: ${env.RESOLVED_DEPLOY_CMD}"

                    // Parse and set additional environment variables
                    if (params.ENVIRONMENT_VARS?.trim()) {
                        echo "Setting additional environment variables..."
                        params.ENVIRONMENT_VARS.split(';').each { envVar ->
                            def trimmed = envVar.trim()
                            if (trimmed && trimmed.contains('=')) {
                                def parts = trimmed.split('=', 2)
                                env."${parts[0].trim()}" = parts[1].trim()
                                echo "  Set: ${parts[0].trim()}=****"
                            }
                        }
                    }
                }
            }
        }

        stage('Pre-Build') {
            when {
                expression { return params.PRE_BUILD_COMMAND?.trim() }
            }
            steps {
                dir(params.WORKING_DIRECTORY) {
                    script {
                        echo "Executing pre-build commands..."
                        executeCommands(params.PRE_BUILD_COMMAND, params.DEBUG_MODE)
                    }
                }
            }
        }

        stage('Build') {
            steps {
                dir(params.WORKING_DIRECTORY) {
                    script {
                        if (env.RESOLVED_BUILD_CMD?.trim()) {
                            echo "Executing build commands..."
                            executeCommands(env.RESOLVED_BUILD_CMD, params.DEBUG_MODE)
                        } else {
                            echo "No build command specified. Skipping build stage."
                        }
                    }
                }
            }
        }

        stage('Test') {
            when {
                expression { return !params.SKIP_TESTS }
            }
            steps {
                dir(params.WORKING_DIRECTORY) {
                    script {
                        if (env.RESOLVED_TEST_CMD?.trim()) {
                            echo "Executing test commands..."
                            executeCommands(env.RESOLVED_TEST_CMD, params.DEBUG_MODE)
                        } else {
                            echo "No test command specified. Skipping test execution."
                        }
                    }
                }
            }
        }

        stage('Archive Artifacts') {
            when {
                expression { return params.ARTIFACT_PATH?.trim() }
            }
            steps {
                dir(params.WORKING_DIRECTORY) {
                    script {
                        echo "Archiving artifacts matching: ${params.ARTIFACT_PATH}"
                        archiveArtifacts artifacts: params.ARTIFACT_PATH, allowEmptyArchive: true, fingerprint: true
                    }
                }
            }
        }

        stage('Deploy') {
            when {
                allOf {
                    expression { return !params.SKIP_DEPLOY }
                    expression { return env.RESOLVED_DEPLOY_CMD?.trim() }
                }
            }
            steps {
                dir(params.WORKING_DIRECTORY) {
                    script {
                        if (params.DEPLOY_ENVIRONMENT == 'production') {
                            input message: "Are you sure you want to deploy to PRODUCTION?",
                                  ok: "Yes, deploy to production",
                                  submitter: "admin,deployers"
                        }

                        echo "Deploying to ${params.DEPLOY_ENVIRONMENT} environment..."
                        executeCommands(env.RESOLVED_DEPLOY_CMD, params.DEBUG_MODE)
                    }
                }
            }
        }

        stage('Post-Build') {
            when {
                expression { return params.POST_BUILD_COMMAND?.trim() }
            }
            steps {
                dir(params.WORKING_DIRECTORY) {
                    script {
                        echo "Executing post-build commands..."
                        executeCommands(params.POST_BUILD_COMMAND, params.DEBUG_MODE)
                    }
                }
            }
        }
    }

    post {
        success {
            echo "Pipeline completed successfully!"
            echo "Project Type: ${params.PROJECT_TYPE} | Environment: ${params.DEPLOY_ENVIRONMENT}"
        }
        failure {
            echo "Pipeline failed! Check the logs above for details."
            echo "Project Type: ${params.PROJECT_TYPE} | Environment: ${params.DEPLOY_ENVIRONMENT}"
        }
        unstable {
            echo "Pipeline completed with warnings (unstable)."
        }
        always {
            echo "Pipeline execution finished. Cleaning up workspace if needed."
        }
    }
}

def executeCommands(String commandString, boolean debugMode) {
    if (!commandString?.trim()) {
        echo "No commands to execute."
        return
    }

    def commands = commandString.split(';').collect { it.trim() }.findAll { it }

    commands.each { cmd ->
        echo ">>> Executing: ${cmd}"
        if (debugMode) {
            sh """
                set -ex
                ${cmd}
            """
        } else {
            sh """
                set -e
                ${cmd}
            """
        }
    }
}

def getDefaultBuildCommand(String projectType) {
    switch (projectType) {
        case 'java':
            return 'mvn clean package -DskipTests'
        case 'nodejs':
            return 'npm ci; npm run build'
        case 'python':
            return 'pip install -r requirements.txt; python setup.py build'
        case 'dotnet':
            return 'dotnet restore; dotnet build --configuration Release'
        case 'custom':
            return ''
        default:
            return ''
    }
}

def getDefaultTestCommand(String projectType) {
    switch (projectType) {
        case 'java':
            return 'mvn test'
        case 'nodejs':
            return 'npm test'
        case 'python':
            return 'python -m pytest tests/ --junitxml=test-results.xml'
        case 'dotnet':
            return 'dotnet test --configuration Release --logger trx'
        case 'custom':
            return ''
        default:
            return ''
    }
}